/// 读取 WBEventManager 自己维护的持久化状态。
+ (id)defaultsObjectForKey:(NSString *)key {
    return [NSUserDefaults.standardUserDefaults objectForKey:[self hashedDefaultsKey:key]];
}

/// 写入或删除 WBEventManager 自己维护的持久化状态。
+ (void)setDefaultsObject:(nullable id)obj forKey:(NSString *)key {
    NSString *hashedKey = [self hashedDefaultsKey:key];
    if (obj) {
        [NSUserDefaults.standardUserDefaults setObject:obj forKey:hashedKey];
    } else {
        [NSUserDefaults.standardUserDefaults removeObjectForKey:hashedKey];
    }
}

